const DEX_CONTRACT_ADDRESS = "0xYourDEXContractAddressHere"; // <<< REPLACE THIS WITH YOUR DEX CONTRACT ADDRESS
const CHAIN_ID = 80001; // Polygon Mumbai Testnet example. Adjust for your target network.

// Minimal ERC20 ABI for interacting with tokens
const ERC20_ABI = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function balanceOf(address account) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "event Transfer(address indexed from, address indexed to, uint256 value)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)"
];

// Simplified DEX ABI. In a real scenario, this would be your actual DEX contract's ABI.
// It assumes a `swap` function that takes tokenIn, tokenOut, and amountIn.
const DEX_ABI = [
    "function swap(address tokenIn, address tokenOut, uint256 amountIn) returns (uint256 amountOut)",
    "function getAmountOut(uint256 amountIn, address tokenIn, address tokenOut) view returns (uint256 amountOut)"
];

// Global Variables
let provider;
let signer;
let userAddress;
let tokenFromDecimals = 18; // Default, will be updated dynamically
let tokenToDecimals = 18; // Default, will be updated dynamically

// UI Elements
const connectWalletBtn = document.getElementById('connectWalletBtn');
const userAddressSpan = document.getElementById('userAddress');
const tokenFromAddressInput = document.getElementById('tokenFromAddress');
const tokenToAddressInput = document.getElementById('tokenToAddress');
const amountInInput = document.getElementById('amountIn');
const tokenFromBalanceSpan = document.getElementById('tokenFromBalance');
const tokenFromAllowanceSpan = document.getElementById('tokenFromAllowance');
const tokenToBalanceSpan = document.getElementById('tokenToBalance');
const approveBtn = document.getElementById('approveBtn');
const swapBtn = document.getElementById('swapBtn');
const statusMessageDiv = document.getElementById('statusMessage');

// Max uint256 for approval (ethers v5.x)
const MAX_UINT256 = ethers.BigNumber.from(2).pow(256).sub(1);
// For ethers v6.x, use: const MAX_UINT256 = ethers.MaxUint256;

function displayStatus(message, isError = false) {
    statusMessageDiv.textContent = message;
    if (isError) {
        statusMessageDiv.classList.add('error');
    } else {
        statusMessageDiv.classList.remove('error');
    }
}

function getERC20Contract(address, useSigner = false) {
    // For ethers v5.x:
    if (!ethers.utils.isAddress(address)) {
    // For ethers v6.x:
    // if (!ethers.isAddress(address)) {
        throw new Error("Invalid ERC20 token address provided.");
    }
    return new ethers.Contract(address, ERC20_ABI, useSigner ? signer : provider);
}

function getDEXContract() {
    // For ethers v5.x:
    if (!ethers.utils.isAddress(DEX_CONTRACT_ADDRESS)) {
    // For ethers v6.x:
    // if (!ethers.isAddress(DEX_CONTRACT_ADDRESS)) {
        throw new Error("Invalid DEX contract address. Please configure DEX_CONTRACT_ADDRESS.");
    }
    return new ethers.Contract(DEX_CONTRACT_ADDRESS, DEX_ABI, signer);
}

function enableButtons(enabled) {
    approveBtn.disabled = !enabled;
    swapBtn.disabled = !enabled;
}

function resetDappState() {
    provider = null;
    signer = null;
    userAddress = null;
    userAddressSpan.textContent = "Not Connected";
    connectWalletBtn.textContent = "Connect Wallet";
    connectWalletBtn.disabled = false;
    tokenFromBalanceSpan.textContent = "0";
    tokenFromAllowanceSpan.textContent = "0";
    tokenToBalanceSpan.textContent = "0";
    enableButtons(false);
    displayStatus("DApp Ready. Please connect your wallet.");
}

async function connectWallet() {
    try {
        displayStatus("Connecting to wallet...");
        if (window.ethereum) {
            // Ethers v5.x
            provider = new ethers.providers.Web3Provider(window.ethereum);
            await provider.send("eth_requestAccounts", []);
            signer = provider.getSigner();

            // Ethers v6.x would look like:
            // provider = new ethers.BrowserProvider(window.ethereum);
            // await provider.send("eth_requestAccounts", []);
            // signer = await provider.getSigner();

            userAddress = await signer.getAddress();
            userAddressSpan.textContent = userAddress;
            displayStatus("Wallet connected: " + userAddress);
            connectWalletBtn.textContent = "Wallet Connected";
            connectWalletBtn.disabled = true;
            enableButtons(true);

            // Listen for account changes
            window.ethereum.on('accountsChanged', (accounts) => {
                if (accounts.length === 0) {
                    displayStatus("Wallet disconnected. Please connect again.", true);
                    resetDappState();
                } else {
                    connectWallet(); // Reconnect to update signer/address
                }
            });

            // Listen for chain changes
            window.ethereum.on('chainChanged', (chainIdHex) => {
                const connectedChainId = parseInt(chainIdHex, 16);
                if (connectedChainId !== CHAIN_ID) {
                    displayStatus(`Wrong network! Please switch to Chain ID ${CHAIN_ID}. Current: ${connectedChainId}`, true);
                    enableButtons(false);
                } else {
                    displayStatus("Correct network detected. Please refresh or reconnect.");
                    // Optional: automatically re-initiate if chain changes back
                    // connectWallet();
                }
            });

            // Initial check for chain ID
            // For ethers v5.x:
            const { chainId } = await provider.getNetwork();
            // For ethers v6.x:
            // const { chainId } = (await provider.getNetwork());
            if (chainId !== CHAIN_ID) {
                displayStatus(`Wrong network! Please switch to Chain ID ${CHAIN_ID}. Current: ${chainId}`, true);
                enableButtons(false);
                return;
            }

            await getBalancesAndAllowance();

        } else {
            displayStatus("Please install MetaMask to use this DApp!", true);
            enableButtons(false);
        }
    } catch (error) {
        displayStatus(`Error connecting wallet: ${error.message}`, true);
        enableButtons(false);
    }
}

async function getBalancesAndAllowance() {
    if (!signer || !userAddress) {
        displayStatus("Please connect your wallet first.", true);
        return;
    }

    const tokenFromAddress = tokenFromAddressInput.value;
    const tokenToAddress = tokenToAddressInput.value;

    // For ethers v5.x:
    if (!ethers.utils.isAddress(tokenFromAddress) || !ethers.utils.isAddress(tokenToAddress)) {
    // For ethers v6.x:
    // if (!ethers.isAddress(tokenFromAddress) || !ethers.isAddress(tokenToAddress)) {
        displayStatus("Please enter valid token addresses.", true);
        tokenFromBalanceSpan.textContent = "N/A";
        tokenFromAllowanceSpan.textContent = "N/A";
        tokenToBalanceSpan.textContent = "N/A";
        return;
    }

    displayStatus("Fetching balances and allowance...");
    try {
        const tokenFromContract = getERC20Contract(tokenFromAddress);
        const tokenToContract = getERC20Contract(tokenToAddress);

        // Get decimals for accurate display and transaction amounts
        tokenFromDecimals = await tokenFromContract.decimals();
        tokenToDecimals = await tokenToContract.decimals();

        // Get balances
        const rawTokenFromBalance = await tokenFromContract.balanceOf(userAddress);
        const rawTokenToBalance = await tokenToContract.balanceOf(userAddress);

        // For ethers v5.x:
        tokenFromBalanceSpan.textContent = ethers.utils.formatUnits(rawTokenFromBalance, tokenFromDecimals);
        tokenToBalanceSpan.textContent = ethers.utils.formatUnits(rawTokenToBalance, tokenToDecimals);
        
        // For ethers v6.x:
        // tokenFromBalanceSpan.textContent = ethers.formatUnits(rawTokenFromBalance, tokenFromDecimals);
        // tokenToBalanceSpan.textContent = ethers.formatUnits(rawTokenToBalance, tokenToDecimals);


        // Get allowance
        const rawAllowance = await tokenFromContract.allowance(userAddress, DEX_CONTRACT_ADDRESS);
        // For ethers v5.x:
        tokenFromAllowanceSpan.textContent = ethers.utils.formatUnits(rawAllowance, tokenFromDecimals);
        // For ethers v6.x:
        // tokenFromAllowanceSpan.textContent = ethers.formatUnits(rawAllowance, tokenFromDecimals);


        displayStatus("Balances and allowance updated.");

    } catch (error) {
        displayStatus(`Error fetching balances/allowance: ${error.message}`, true);
        tokenFromBalanceSpan.textContent = "Error";
        tokenFromAllowanceSpan.textContent = "Error";
        tokenToBalanceSpan.textContent = "Error";
    }
}

async function approveToken() {
    if (!signer || !userAddress) {
        displayStatus("Please connect your wallet first.", true);
        return;
    }

    const tokenFromAddress = tokenFromAddressInput.value;
    // For ethers v5.x:
    if (!ethers.utils.isAddress(tokenFromAddress)) {
    // For ethers v6.x:
    // if (!ethers.isAddress(tokenFromAddress)) {
        displayStatus("Please enter a valid Token IN address.", true);
        return;
    }

    displayStatus(`Approving max allowance for ${tokenFromAddress} to DEX contract...`);
    try {
        // Use the signer to send the transaction
        const tokenFromContractWithSigner = getERC20Contract(tokenFromAddress, true); 
        const tx = await tokenFromContractWithSigner.approve(DEX_CONTRACT_ADDRESS, MAX_UINT256);
        
        displayStatus(`Approval transaction sent: ${tx.hash}. Waiting for confirmation...`);
        await tx.wait(); // Wait for the transaction to be mined
        displayStatus("Token approval successful!");
        await getBalancesAndAllowance(); // Refresh allowance status
    } catch (error) {
        displayStatus(`Error during token approval: ${error.message}`, true);
    }
}

async function swapTokens() {
    if (!signer || !userAddress) {
        displayStatus("Please connect your wallet first.", true);
        return;
    }

    const tokenFromAddress = tokenFromAddressInput.value;
    const tokenToAddress = tokenToAddressInput.value;
    const amountIn = amountInInput.value;

    // For ethers v5.x:
    if (!ethers.utils.isAddress(tokenFromAddress) || !ethers.utils.isAddress(tokenToAddress)) {
    // For ethers v6.x:
    // if (!ethers.isAddress(tokenFromAddress) || !ethers.isAddress(tokenToAddress)) {
        displayStatus("Please enter valid token addresses.", true);
        return;
    }
    if (!amountIn || isNaN(amountIn) || parseFloat(amountIn) <= 0) {
        displayStatus("Please enter a valid amount to swap.", true);
        return;
    }

    displayStatus(`Initiating swap for ${amountIn} of ${tokenFromAddress}...`);
    try {
        // Convert human-readable amount to BigNumber in wei using token decimals
        // For ethers v5.x:
        const amountInWei = ethers.utils.parseUnits(amountIn, tokenFromDecimals);
        // For ethers v6.x:
        // const amountInWei = ethers.parseUnits(amountIn, tokenFromDecimals);

        const dexContractWithSigner = getDEXContract(); // Uses signer by default
        const tx = await dexContractWithSigner.swap(
            tokenFromAddress,
            tokenToAddress,
            amountInWei
        );
        displayStatus(`Swap transaction sent: ${tx.hash}. Waiting for confirmation...`);
        await tx.wait(); // Wait for the transaction to be mined
        displayStatus("Token swap successful!");
        await getBalancesAndAllowance(); // Refresh balances
        amountInInput.value = ''; // Clear amount input
    } catch (error) {
        displayStatus(`Error during token swap: ${error.message}`, true);
    }
}

// Event Listeners
document.addEventListener('DOMContentLoaded', () => {
    connectWalletBtn.addEventListener('click', connectWallet);
    approveBtn.addEventListener('click', approveToken);
    swapBtn.addEventListener('click', swapTokens);

    // Refresh balances/allowance when token addresses change
    tokenFromAddressInput.addEventListener('change', getBalancesAndAllowance);
    tokenToAddressInput.addEventListener('change', getBalancesAndAllowance);

    // Initial check if wallet is already connected (e.g., after refresh)
    if (window.ethereum && window.ethereum.selectedAddress) {
        connectWallet();
    }
});
